<template>
  <div class="sample">
    <van-sticky>
      <van-nav-bar title="样品信息" left-arrow @click-left="onClickLeft" />
    </van-sticky>
    <el-form
      :model="ruleForm"
      :rules="rules"
      ref="ruleForm"
      label-width="100px"
      class="demo-ruleForm"
    >
      <el-form-item label="产品类型" prop="type">
        <el-select
          size="mini"
          style="width: 100%"
          v-model="ruleForm.type"
          filterable
          placeholder="请选择产品类型"
          @change="onProductId"
        >
          <el-option
            v-for="item in typeoptions"
            :key="item.value"
            :label="item.label"
            :value="item.value"
          >
          </el-option>
        </el-select>
      </el-form-item>
      <el-form-item label="选择产品" prop="productId">
        <el-select
          class=""
          style="width: 100%"
          size="mini"
          v-model="ruleForm.productId"
          filterable
          placeholder="请选择产品名称"
          @change="onProductname"
        >
          <el-option
            v-for="item in productIdoptions"
            :key="item.value"
            :label="item.label"
            :value="item.value"
          >
          </el-option>
        </el-select>
      </el-form-item>
      <el-form-item label="判定依据" v-show="list.length > 0" prop="checkList">
        <el-checkbox-group
          size="mini"
          v-model="ruleForm.checkList"
          class="checklist checklist_h1 animate__animated animate__fadeInDown"
        >
          <el-checkbox
            v-for="(item, i) in list"
            :key="i"
            :value="item"
            :label="item.label"
          ></el-checkbox>
        </el-checkbox-group>
      </el-form-item>
      <el-form-item label="规格等级" prop="modelId">
        <el-input size="mini" v-model="ruleForm.modelId"></el-input>
      </el-form-item>
      <el-form-item label="产品批次" prop="productNumber">
        <el-input size="mini" v-model="ruleForm.productNumber"></el-input>
      </el-form-item>
      <el-form-item label="样品数量" prop="objectCount">
        <el-input size="mini" v-model="ruleForm.objectCount"></el-input>
      </el-form-item>
      <el-form-item label="样品产地" prop="productCompanyName">
        <el-input size="mini" v-model="ruleForm.productCompanyName"></el-input>
      </el-form-item>
      <el-form-item label="样品类型" prop="sampleType">
        <el-select
          size="mini"
          v-model="ruleForm.sampleType"
          filterable
          placeholder="样品类型"
        >
          <el-option
            v-for="item in sampleTypeoptions"
            :key="item.value"
            :label="item.label"
            :value="item.value"
          >
          </el-option>
        </el-select>
      </el-form-item>
    </el-form>

    <div class="sample_fix" style="z-index: 100">
      <!-- <el-button type="primary"
        >立即创建</el-button
      > -->
      <van-button round block type="info" @click="submitForm('ruleForm')" >保存</van-button>
    </div>

    <div style="z-index: 10">
      <ul class="ul">
        <li
          class="li animate__animated animate__fadeInDown"
          v-for="item in ruleForm.checkitem_arr"
          :key="item.id"
        >
          <Checkitem
            :check_items="check_items"
            :add_list_item="add_list_item"
            :index="item.id"
            @del="del"
            @setselect1="setselect1"
            @setselect2="setselect2"
            @handleChange="handleChange"
          />
        </li>
      </ul>
      <van-row>
        <van-col
          span="24"
          class="istalist_jia animate__animated animate__fadeInDown"
           
        >
          <van-button
            style="width: 44px"
            @click="add"
            icon="plus"
            type="primary"
            round
        /></van-col>
      </van-row>
      <div class="istalist_bottom"></div>
    </div>
  </div>
</template>
<script>
import Checkitem from "../../components/Checkitem.vue";
import { nanoid } from "nanoid";
import { Toast } from "vant";
import { mapMutations } from "vuex";
import {
  getproducttype,
  getproduct,
  getproductbasis,
  getcheckitem,
} from "../../utils/http/api";
export default {
  name: "sample",
  components: {
    Checkitem,
  },

  data() {
    return {
      ruleForm: {
        type: "",
        productId: "",
        modelId: "",
        productNumber: "",
        objectCount: "",
        productCompanyName: "",
        sampleType: "",
        checkitem_arr: [],
        checkList: [],
      },
      rules: {
        productId: [{ required: true, message: "选择产品", trigger: "change" }],
        modelId: [{ required: true, message: "不能为空", trigger: "blur" }],
        productNumber: [
          { required: true, message: "不能为空", trigger: "blur" },
        ],
        objectCount: [{ required: true, message: "不能为空", trigger: "blur" }],
        productCompanyName: [
          { required: true, message: "不能为空", trigger: "blur" },
        ],
        sampleType: [
          { required: true, message: "不能为空", trigger: "change" },
        ],
        type: [{ required: true, message: "选择产品类型", trigger: "change" }],

        checkList: [
          {
            type: "array",
            required: true,
            message: "请至少选择一个判定依据",
            trigger: "change",
          },
        ],
      },

      list: [],
      check_items: [],
      typeoptions: [],
      productIdoptions: [],
      sampleTypeoptions: [
        { label: "单一", value: 1 },
        { label: "复合", value: 2 },
      ],
    };
  },
  created() {
    this.init();
    this.add();
  },

  computed: {
    add_list_item() {
      let arr = [];
      this.ruleForm.checkList.map((item) => {
        this.list.map((val) => {
          if (val.label === item) {
            arr.push(val);
          }
        });
      });
      return arr;
    },
  },
  methods: {
    ...mapMutations(["setsampleList"]),
    init() {
      getproducttype().then((res) => {
        res.data.data.forEach((item) => {
          this.typeoptions.push(item);
        });
      });
    },
    add() {
      let obj = {
        id: nanoid(),
        checkItemId: "",
        standardId: "",
        checkTimes: 1,
      };
      this.ruleForm.checkitem_arr.push(obj);
    },
    onProductId(value) {
      // 清除产品ID
      this.ruleForm.productId = "";
      // 清除产品
      this.productIdoptions = [];
      // 清除判定依据
      this.list = [];
      // 清除样品列表
      this.ruleForm.checkitem_arr = [];
      this.add();
      getproduct(value).then((res) => {
        res.data.data.map((item) => {
          this.productIdoptions.push({ label: item.label, value: item.value });
        });
      });
    },
    onProductname(value) {
      this.list = [];
      this.ruleForm.checkList = [];
      // 判定的依据
      getproductbasis(value).then((res) => {
        res.data.data.map((item) => {
          this.list.push(item);
        });
      });
      this.check_items = [];
      // 检测项目
      getcheckitem(value).then((res) => {
        res.data.data.map((item) => {
          this.check_items.push({
            label: item.itemName,
            value: item.itemId,
          });
        });
      });
    },

    del(index) {
      let willdelobj = this.ruleForm.checkitem_arr.filter((item) => {
        return item.id === index;
      })[0];
      let willdelid = this.ruleForm.checkitem_arr.indexOf(willdelobj);
      this.ruleForm.checkitem_arr.splice(willdelid, 1);
    },
    setselect1(index, value) {
      this.ruleForm.checkitem_arr.map((item) => {
        if (item.id === index) {
          item.checkItemId = value;
        }
      });
    },
    setselect2(index, value) {
      this.ruleForm.checkitem_arr.map((item) => {
        if (item.id === index) {
          item.standardId = value;
        }
      });
    },
    handleChange(index, value) {
      this.ruleForm.checkitem_arr.map((item) => {
        if (item.id === index) {
          item.checkTimes = value;
        }
      });
    },
    submitForm(values) {
      console.log(values);

      this.$refs[values].validate((valid) => {
        if (valid) {
          let FormItem = {
            productId: this.ruleForm.productId,
            modelId: this.ruleForm.modelId,
            productNumber: this.ruleForm.productNumber,
            objectCount: this.ruleForm.objectCount,
            productCompanyName: this.ruleForm.productCompanyName,
            sampleType: this.ruleForm.sampleType,
            productStandardSource: "",
            checkList: [],
            productname: "",
          };
          this.ruleForm.checkitem_arr.forEach((item) => {
            FormItem.checkList.push({
              checkItemId: item.checkItemId,
              standardId: item.standardId,
              checkTimes: item.checkTimes,
            });
          });
          this.ruleForm.checkList.map((item, i) => {
            if (this.ruleForm.checkList.length - 1 === i) {
              FormItem.productStandardSource += item.split(",")[0];
            } else {
              FormItem.productStandardSource += item.split(",")[0] + ",";
            }
          });
          FormItem.productname = this.productIdoptions.filter((item) => {
            return item.value === this.ruleForm.productId;
          })[0].label;
          this.setsampleList(FormItem);
          this.$router.go(-1);
        } else {
          console.log("error submit!!");

          return false;
        }
      });
    },
    onClickLeft() {
      this.$router.go(-1);
    },
  },
};
</script>

<style lang="less">
.input_massage {
  // input {
  //   border: 1px solid #ee0a24;
  // }
  input::-webkit-input-placeholder {
    color: #ee0a24;
  }
}

.el-select-dropdown__item {
  // font-size: 8px !important;
}
.el-select-dropdown__list {
  max-width: 350px !important;
}
.el-select-dropdown__item {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.demo-ruleForm {
  padding: 10px 16px;
  box-sizing: border-box;
  // display: flex;
  // align-items: center;
  .el-form-item__label {
    width: 88px !important;
  }
  .el-form-item {
    // margin: 0px !important;
  }
  .el-form-item--mini {
    margin-bottom: 0px !important;
  }
}
.sample {
  width: 7.5rem;
  height: 13.34rem;
  background: white;

  .sample_fix {
    position: fixed;
    bottom: 0px;
    background: @gray-1;
    width: 7.5rem;
    padding: 0.32rem;
    box-sizing: border-box;
  }
  .sample_select {
    width: 100%;
    // height: 1.9rem;
    display: flex;
    // justify-content: center;
    align-items: center;
    padding: 0.2rem 0.32rem;
    box-sizing: border-box;
    > div {
      width: 100%;
      display: flex;
      flex-direction: column;

      align-items: center;
      justify-content: space-between;
    }
    h1 {
      font-size: 12px;
      font-weight: 400;
      width: 86.8px;
    }
  }
  .checklist_h1 {
    width: 100%;

    .el-checkbox__label {
      width: 300px;
      overflow: hidden;
      text-overflow: ellipsis;
      white-space: nowrap;
    }
    .el-checkbox {
      overflow: hidden;
      display: flex;
      align-items: center;
      font-size: 10px !important;
    }
    .checklist {
      padding: 0 0.32rem;
      word-wrap: break-word;

      display: flex;
      flex-direction: column;
    }
  }

  .li {
    margin: 8px;
    padding: 4px;
    box-sizing: border-box;
    background: @gray-2;
    border-radius: 10px;
  }
  .van-col--24 {
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .istalist_bottom {
    width: 100%;
    height: 3rem;
    background: white;
  }
}
</style>
