<template>
  <div class="checkitem">
    <van-icon name="cross" class="cha" @click="del(index)" />
    <div class="sample_select">
      <h1>检验项目</h1>

      <el-select
        size="mini"
        v-model="value"
        filterable
        placeholder="检验项目"
        @change="changeValue1"
      >
        <el-option
          v-for="(item) in check_items"
          :key="item.value"
          :label="item.label"
          :value="item.value"
        >
        </el-option>
      </el-select>
    </div>
    <div class="sample_select">
      <h1>检验依据</h1>

      <el-select
        size="mini"
        v-model="value1"
        filterable
        placeholder="检验依据"
        @change="changeValue2"
      >
        <el-option
          v-for="item in add_list_item"
          :key="item.value"
          :label="item.label"
          :value="item.value"
        >
        </el-option>
      </el-select>
    </div>
    <div class="sample_select">
      <h1>检测样次</h1>

      <el-input-number
        size="mini"
        v-model="num"
        @change="handleChange"
        :min="1"
        :max="10"
        label="描述文字"
      ></el-input-number>
    </div>
  </div>
</template>

<script>
export default {
  props: ["index", "check_items", "add_list_item"],
  created() {},
  data() {
    return {
      num: 1,
      options: [
        {
          value: "选项1",
          label: "黄金糕1黄金糕黄",
        },
        {
          value: "选项2",
          label: "双皮奶",
        },
        {
          value: "选项3",
          label: "蚵仔煎",
        },
        {
          value: "选项4",
          label: "龙须面",
        },
        {
          value: "选项5",
          label: "北京烤鸭",
        },
      ],
      value: "",
      options1: [
        {
          value: "选项1",
          label: "黄金糕1黄金糕黄",
        },
        {
          value: "选项2",
          label: "双皮奶",
        },
        {
          value: "选项3",
          label: "蚵仔煎",
        },
        {
          value: "选项4",
          label: "龙须面",
        },
        {
          value: "选项5",
          label: "北京烤鸭",
        },
      ],
      value1: "",
    };
  },
  methods: {
    del(index) {
      this.$emit("del", index);
    },
    changeValue1(value) {
      this.$emit("setselect1", this.index, value);
    },
    changeValue2(value) {
      this.$emit("setselect2", this.index, value);
    },
    handleChange(value) {
      this.$emit("handleChange", this.index, value);
    },
  },
};
</script>


<style lang="less">
.checkitem {
  display: flex;
  flex-direction: column;
  position: relative;
  .cha {
    position: absolute;
    right: -5px;
    top: -10px;
    width: 20px;
    font-size: 20px;
    float: right;
    border: 2px solid @gray-6;
    color: @gray-7;
    border-radius: 50%;
  }
}
</style>